import { motion } from "framer-motion";
import clsx from "clsx";

export function StepLayout({ children, className }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 6 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.2 }}
      className={clsx(
        "w-full max-w-4xl mx-auto px-6 py-6",
        className
      )}
    >
      {children}
    </motion.div>
  );
}
